const normalized = $('Normaliser Filtrer Anti-Boucle').first().json;
const agentOutput = $('Agent Eden').first().json.output || "Bonjour ! Je suis Eden de Bobge's Multi-Service. Comment puis-je vous aider ?";
function extractNum(s) { return String(s||'').replace(/@[\w.]+/g,'').replace(/[^0-9]/g,''); }
function isValid(n) { return !!(n && /^[0-9]{8,15}$/.test(n)); }
let to = normalized.replyTo || '';
if (!isValid(to) && !normalized.isGroup) {
  if (isValid(normalized.cleanNumber)) to = normalized.cleanNumber;
  else if (normalized.isNormal) to = extractNum(normalized.remoteJid);
}
const canSend = normalized.isGroup ? true : isValid(to);
return [{ json: { to, text: agentOutput, canSend } }];

try {
  const agentOutput = $('Agent Eden').first().json.output || '';
  const norm = $('Normaliser Filtrer Anti-Boucle').first().json;
  const agentSteps = $('Agent Eden').first().json;

  const outputLow = agentOutput.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const messageEntrant = (norm.messageBody || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

  const visiteMots = ['visite programm','rdv confirm','rendez-vous confirm','visite confirm','visite fix','rdv fix'];
  const hasVisiteAgent = visiteMots.some(kw => outputLow.includes(kw));

  const visiteMotsProspect = [
    'je veux visiter','je voudrais visiter','visiter le bien','visiter la maison',
    'faire une visite','organiser une visite','ok pour la visite','oui pour la visite',
    'je confirme la visite','confirme la visite','rdv pour voir','voir le bien',
    'voir l appartement','voir la villa','voir la maison','voir le terrain','voir le studio'
  ];
  const hasVisiteProspect = visiteMotsProspect.some(kw => messageEntrant.includes(kw));
  const hasVisite = hasVisiteAgent || hasVisiteProspect;

  const hasImageRequest = ['image','images','photo','photos','video','videos','visuel','visuels'].some(kw => messageEntrant.includes(kw));

  let refs = [];
  try {
    const stepsStr = JSON.stringify(agentSteps);
    const refMatches = stepsStr.match(/\[REF_INTERNE:([^\]]+)\]/gi);
    if (refMatches) refs = [...new Set(refMatches.map(m => m.replace('[REF_INTERNE:', '').replace(']', '')))];
    if (refs.length === 0) {
      const refMatchesOld = stepsStr.match(/\[REF:([^\]]+)\]/gi);
      if (refMatchesOld) refs = [...new Set(refMatchesOld.map(m => m.replace('[REF:', '').replace(']', '')))];
    }
  } catch(e) {}

  const sd = $getWorkflowStaticData('global');
  const prospectKey = 'prospect_refs_' + (norm.cleanNumber || norm.remoteJid);
  if (refs.length > 0) { sd[prospectKey] = { refs, timestamp: Date.now() }; }
  else if (sd[prospectKey] && (Date.now() - sd[prospectKey].timestamp) < 3600000) { refs = sd[prospectKey].refs || []; }

  const refBien = refs.length > 0 ? refs[0] : '';
  const allRefs = refs.join(', ');

  let bienType='', bienLocalisation='', bienPrix='', bienSurface='', bienCaracteristiques='', agentNom='', agentTel='';
  try {
    const stepsStr = JSON.stringify(agentSteps);
    const typeMatch    = stepsStr.match(/Type:\s*([^|\\n"]+)/i);
    const locMatch     = stepsStr.match(/Localisation:\s*([^\\n"]+)/i);
    const prixMatch    = stepsStr.match(/Prix:\s*([^\\n"]+)/i);
    const surfaceMatch = stepsStr.match(/Surface:\s*([^\\n"]+)/i);
    const detailsMatch = stepsStr.match(/D[eé]tails:\s*([^\\n"\[]+)/i);
    if (typeMatch)    bienType             = typeMatch[1].trim();
    if (locMatch)     bienLocalisation     = locMatch[1].trim();
    if (prixMatch)    bienPrix             = prixMatch[1].trim();
    if (surfaceMatch) bienSurface          = surfaceMatch[1].trim();
    if (detailsMatch) bienCaracteristiques = detailsMatch[1].trim().substring(0, 300);
    const confidentielMatch = stepsStr.match(/CONFIDENTIEL_NE_PAS_COMMUNIQUER_AU_PROSPECT[^:]*—\s*Agent:\s*([^/\\]+)\s*\/\s*Tel:\s*([^\]\\]+)/i);
    if (confidentielMatch) { agentNom = confidentielMatch[1].trim().replace(/["']/g,''); agentTel = confidentielMatch[2].trim().replace(/["']/g,''); }
  } catch(e) { console.log('[POST TRAITEMENT] Erreur extraction détails:', e.message); }

  const parts = [];
  if (bienType)             parts.push('Type: ' + bienType);
  if (bienLocalisation)     parts.push('Localisation: ' + bienLocalisation);
  if (bienPrix)             parts.push('Prix: ' + bienPrix);
  if (bienSurface)          parts.push('Surface: ' + bienSurface);
  if (bienCaracteristiques) parts.push('Caractéristiques: ' + bienCaracteristiques);
  let bienDetails = parts.join('\n');
  if (!bienDetails && refs.length > 0) bienDetails = 'Référence: ' + refBien;

  let prospectNomComplet = norm.pushName || '';
  let dateVisite = 'À planifier';
  let heureVisite = '';
  try {
    const nomDirectMatch = agentOutput.match(/(?:Parfait|Merci)[,\s]+([A-ZÉÈÀÂÏÎÔÙÛa-zéèàâïîôùû\s]+?)(?:[,!.]|\s+visite)/i);
    if (nomDirectMatch && nomDirectMatch[1].trim().split(/\s+/).length >= 2) prospectNomComplet = nomDirectMatch[1].trim();
    const dateMatch = agentOutput.match(/(lundi|mardi|mercredi|jeudi|vendredi|samedi|dimanche|demain|aujourd'hui|\d{1,2}[\/\-\.\s]\d{1,2}(?:[\/\-\.\s]\d{2,4})?|\d{1,2}\s+(?:janvier|f[ée]vrier|mars|avril|mai|juin|juillet|ao[uû]t|septembre|octobre|novembre|d[ée]cembre)(?:\s+\d{4})?)/i);
    if (dateMatch) dateVisite = dateMatch[0].trim();
    const heureMatch = agentOutput.match(/(\d{1,2}h\d{0,2}|\d{1,2}:\d{2}|\d{1,2}\s*heures?)/i);
    if (heureMatch) heureVisite = heureMatch[0].trim();
  } catch(e) {}

  const dateHeureVisite = heureVisite ? dateVisite + ' à ' + heureVisite : dateVisite;
  console.log('[POST TRAITEMENT] hasVisite:', hasVisite, '| Agent:', hasVisiteAgent, '| Prospect:', hasVisiteProspect, '| refs:', allRefs);

  return [{ json: {
    hasVisite, hasImageRequest,
    ref_bien: refBien, all_refs: allRefs,
    bien_details: bienDetails,
    bien_type: bienType, bien_localisation: bienLocalisation,
    bien_prix: bienPrix, bien_surface: bienSurface,
    bien_caracteristiques: bienCaracteristiques,
    agent_nom: agentNom, agent_tel: agentTel,
    date_visite: dateHeureVisite,
    prospect_numero: norm.cleanNumber || norm.replyTo || '',
    prospect_nom: prospectNomComplet,
    agentOutput,
    logEntry: {
      numero_prospect: norm.cleanNumber || norm.replyTo || '',
      nom_prospect: prospectNomComplet,
      message_entrant: (norm.messageBody || '').substring(0, 500),
      reponse_agent: agentOutput.substring(0, 500),
      ref_mentionne: allRefs,
      horodatage: new Date().toISOString()
    }
  }];
} catch(e) { console.log('[POST TRAITEMENT] Erreur:', e.message); return []; }
